            sh:resultMessage "Every geojson:FeatureCollection must have at least one focal-prop:lesniTyp whose value is an IRI resource." ;
            sh:resultPath focal-prop:lesniTyp ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Every geojson:FeatureCollection must have at least one focal-prop:lesniTyp whose value is an IRI resource." ;
                    sh:minCount 1 ;
                    sh:name "lesniTyp" ;
                    sh:nodeKind sh:IRI ;
                    sh:path focal-prop:lesniTyp ] ] .

